+    async fn ensure_socket_mode_running(&mut self) -> FcpResult<bool> {
+        if let Some(task) = &self.socket_mode_task
+            && !task.is_finished()
+            && *self.socket_mode_running.read().await
+        {
+            return Ok(false);
+        }
+
+        self.stop_socket_mode().await;
