+        let socket_mode_token =
+            self.socket_mode_token
+                .clone()
+                .ok_or_else(|| FcpError::InvalidRequest {
+                    code: 1003,
+                    message: "Socket Mode token not configured".into(),
+                })?;
+
+        let mut socket_client =
