+
+fn topic_allowed(topic: &str, patterns: &[String]) -> bool {
+    if patterns.is_empty() {
+        return true;
+    }
+
+    patterns.iter().any(|pattern| {
+        if pattern == "*" {
+            return true;
+        }
+        if let Some(prefix) = pattern.strip_suffix('*') {
+            return topic.starts_with(prefix);
+        }
+        pattern == topic
+    })
+}
